+        </button>
+        <button className="hover:text-blue-600 mt-auto">
+          <i className="fas fa-cog text-xl"></i>
+        </button>
+      </div>
+
+      {/* Chat list + messages */}
+      <div className="w-2/5 border-r bg-white flex flex-col">
+        <div className="p-4 border-b font-bold text-lg">Room: {room}</div>
+        <div className="flex-1 overflow-y-auto p-4 space-y-2">
+          {chat.map((msg, i) => {
+            const isSelf = msg.sender === username;
+            return (
+              <div
+                key={i}
+                className={`flex ${isSelf ? "justify-end" : "justify-start"}`}
+              >
+                <div
+                  className={`max-w-xs px-4 py-2 rounded-lg shadow ${
+                    isSelf
+                      ? "bg-blue-500 text-white rounded-br-none"
+                      : "bg-gray-100 text-gray-800 rounded-bl-none"
+                  }`}
+                >
+                  {!isSelf && (
+                    <div className="font-semibold text-xs mb-1">
+                      {msg.sender}
+                    </div>
+                  )}
+                  <div>{msg.text}</div>
+                  <div className="text-[10px] text-right mt-1 text-gray-300">
+                    {msg.time}
+                  </div>
+                </div>
+              </div>
+            );
+          })}
+          <div ref={bottomRef} />
+        </div>
+
