import React, { useEffect, useState, useRef } from "react";
import { useSearchParams } from "react-router-dom";
import { io } from "socket.io-client";
import MessageBubble from "./MessageBubble";

const socket = io("http://localhost:3000");

export default function ChatRoom() {
  const [searchParams] = useSearchParams();
  const username = searchParams.get("username");
  const room = searchParams.get("room");

  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);
  const [users, setUsers] = useState([]);
  const bottomRef = useRef(null);

  useEffect(() => {
    if (username && room) {
      socket.emit("join-room", { username, room });

      socket.on("receive-message", (data) => {
        setChat((prev) => [...prev, data]);
      });

      socket.on("user-list", (data) => {
        setUsers(data);
      });
    }

    return () => socket.disconnect();
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat]);

  const sendMessage = () => {
    if (message.trim()) {
      socket.emit("send-message", { text: message });
      setMessage("");
    }
  };

  return (
    <div className="h-screen flex bg-gradient-to-br from-blue-50 to-blue-100">
      {/* Sidebar: Room users */}
      <div className="w-64 bg-white border-r p-4 overflow-y-auto">
        <h3 className="text-lg font-semibold mb-3 text-blue-600">Users in {room}</h3>
        <div className="space-y-2">
          {users.map((u) => (
            <div
              key={u.id}
              className={`p-2 rounded text-sm ${
                u.username === username ? "bg-blue-100 font-bold" : ""
              }`}
            >
              {u.username}
            </div>
          ))}
        </div>
      </div>

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col p-6">
        <h2 className="text-2xl font-bold text-gray-800 mb-4">Room: {room}</h2>

        <div className="flex-1 overflow-y-auto bg-white p-4 rounded shadow-inner">
          {chat.map((msg, i) => (
            <MessageBubble
              key={i}
              sender={msg.sender}
              text={msg.text}
              time={msg.time}
              isSelf={msg.sender === username}
            />
          ))}
          <div ref={bottomRef} />
        </div>

        {/* Message input */}
        <div className="mt-4 flex gap-2">
          <input
            className="flex-1 border p-2 rounded shadow-sm"
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="Type a message..."
          />
          <button
            onClick={sendMessage}
            className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
          >
            Send
          </button>
        </div>
      </div>
    </div>
  );
}
